import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.println("Enter a string:");
        String input = scanner.nextLine();

        // Define the size of the buffer
        int bufferSize = 10;

        // Limit the input to the size of the buffer
        if (input.length() > bufferSize) {
            System.out.println("Input exceeds buffer size. Truncating input...");
            input = input.substring(0, bufferSize);
        }

        char[] buffer = new char[bufferSize];

        // Copy the user input into the buffer
        input.getChars(0, input.length(), buffer, 0);

        System.out.println("Buffer contents: " + new String(buffer));
    }
}

### Explanation:
